import{c as t,Q as a,j as i,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Code Review — 多代理 PR 自動審查完整指南","description":"","frontmatter":{"title":"Code Review — 多代理 PR 自動審查完整指南","source":"https://code.claude.com/docs/en/code-review","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/22-code-review.md","filePath":"research/best-practices/22-code-review.md","lastUpdated":1779935873000}'),n={name:"research/best-practices/22-code-review.md"};function r(l,e,o,d,h,p){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="code-review-—-多代理-pr-自動審查完整指南" tabindex="-1">Code Review — 多代理 PR 自動審查完整指南 <a class="header-anchor" href="#code-review-—-多代理-pr-自動審查完整指南" aria-label="Permalink to &quot;Code Review — 多代理 PR 自動審查完整指南&quot;">​</a></h1><blockquote><p>來源：<a href="https://code.claude.com/docs/en/code-review" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/code-review</a><br> 補充來源：<a href="https://claude.com/blog/code-review" target="_blank" rel="noreferrer">https://claude.com/blog/code-review</a><br> 收錄日期：2026-05-01<br> 涵蓋：Code Review 運作原理、Setup 流程、Severity 等級、REVIEW.md 自訂、@claude review 指令、定價、troubleshooting</p></blockquote><hr><h2 id="一、功能概述" tabindex="-1">一、功能概述 <a class="header-anchor" href="#一、功能概述" aria-label="Permalink to &quot;一、功能概述&quot;">​</a></h2><p><strong>Code Review</strong> 是 Claude Code 的多代理 PR 自動審查功能（research preview，Team / Enterprise 訂閱）。 一旦啟用，Claude 分析 GitHub PR 並以 inline comments 形式標出：邏輯錯誤、安全漏洞、邊界情況破壞、潛在回歸問題。</p><p>官方統計數字（Anthropic 內部驗證）：</p><ul><li>工程師程式碼產出成長 <strong>200%</strong></li><li>獲得實質性 review comment 的 PR 比例：<strong>16% → 54%</strong></li><li>誤報率（false positive rate）：<strong>&lt; 1%</strong></li></ul><p>Zero Data Retention 組織不可用。</p><hr><h2 id="二、運作原理" tabindex="-1">二、運作原理 <a class="header-anchor" href="#二、運作原理" aria-label="Permalink to &quot;二、運作原理&quot;">​</a></h2><h3 id="_2-1-審查流程" tabindex="-1">2.1 審查流程 <a class="header-anchor" href="#_2-1-審查流程" aria-label="Permalink to &quot;2.1 審查流程&quot;">​</a></h3><ol><li>PR 開啟 / push / 手動觸發 → 啟動多個平行 agent</li><li>每個 agent 分析 diff + 周邊程式碼（各負責不同類別的問題）</li><li>Verification pass：對候選問題驗證對實際程式碼行為，過濾誤報</li><li>去重 + 按 severity 排序 → 發佈為 PR inline comments</li><li>若無問題：發佈簡短確認 comment</li><li>平均完成時間：<strong>20 分鐘</strong></li></ol><h3 id="_2-2-severity-等級" tabindex="-1">2.2 Severity 等級 <a class="header-anchor" href="#_2-2-severity-等級" aria-label="Permalink to &quot;2.2 Severity 等級&quot;">​</a></h3><table tabindex="0"><thead><tr><th>標記</th><th>等級</th><th>含義</th></tr></thead><tbody><tr><td>🔴</td><td><strong>Important</strong></td><td>merge 前應修復的 bug</td></tr><tr><td>🟡</td><td><strong>Nit</strong></td><td>次要問題，值得修但不阻塞</td></tr><tr><td>🟣</td><td><strong>Pre-existing</strong></td><td>存在於 codebase 但非此 PR 引入的 bug</td></tr></tbody></table><p>每個 finding 含<strong>可展開的 extended reasoning</strong>，說明 Claude 為何標記此問題及驗證方式。</p><h3 id="_2-3-check-run-輸出" tabindex="-1">2.3 Check Run 輸出 <a class="header-anchor" href="#_2-3-check-run-輸出" aria-label="Permalink to &quot;2.3 Check Run 輸出&quot;">​</a></h3><p>GitHub Checks tab 出現「<strong>Claude Code Review</strong>」check run（結論永遠為 neutral，不阻擋 merge）。 Check run Details 含完整 finding 表格（按 severity 排序）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| Severity     | File:Line                  | Issue                         |</span></span>
<span class="line"><span>|--------------|---------------------------|-------------------------------|</span></span>
<span class="line"><span>| 🔴 Important | src/auth/session.ts:142   | Token refresh races with logout |</span></span>
<span class="line"><span>| 🟡 Nit       | src/auth/session.ts:88    | parseExpiry returns 0 on malformed input |</span></span></code></pre></div><p>用 CI 腳本讀取 severity 統計（machine-readable format）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repos/OWNER/REPO/check-runs/CHECK_RUN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.output.text | split(&quot;bughunter-severity: &quot;)[1] | split(&quot; --&gt;&quot;)[0] | fromjson&#39;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 回傳：{&quot;normal&quot;: 2, &quot;nit&quot;: 1, &quot;pre_existing&quot;: 0}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># &quot;normal&quot; = Important findings 數量</span></span></code></pre></div><h3 id="_2-4-rating-機制" tabindex="-1">2.4 Rating 機制 <a class="header-anchor" href="#_2-4-rating-機制" aria-label="Permalink to &quot;2.4 Rating 機制&quot;">​</a></h3><p>每則 review comment 附帶 👍 / 👎。 Anthropic 收集 PR merge 後的 reaction 統計 → 用於調整 reviewer 品質。 回覆 inline comment <strong>不會</strong>觸發 Claude 重新回應或更新 PR。</p><hr><h2 id="三、setup-流程" tabindex="-1">三、Setup 流程 <a class="header-anchor" href="#三、setup-流程" aria-label="Permalink to &quot;三、Setup 流程&quot;">​</a></h2><blockquote><p>前提：需要 Claude 組織 admin 權限 + GitHub 組織 GitHub App 安裝權限。</p></blockquote><ol><li>前往 <code>claude.ai/admin-settings/claude-code</code> → Code Review 區塊 → <strong>Setup</strong></li><li>安裝 <strong>Claude GitHub App</strong> 到 GitHub 組織（需要 Contents read/write、Issues read/write、Pull requests read/write）</li><li>選擇要啟用 Code Review 的 <strong>repositories</strong></li><li>為每個 repo 設定 <strong>Review Behavior</strong>： <ul><li><strong>Once after PR creation</strong>：PR 開啟或從 draft 轉 ready 時執行一次</li><li><strong>After every push</strong>：每次 push 觸發（成本最高，自動解析已修復的 thread）</li><li><strong>Manual</strong>：僅在 <code>@claude review</code> comment 時執行</li></ul></li></ol><p>驗證：開一個測試 PR → 數分鐘內出現「Claude Code Review」check run。</p><hr><h2 id="四、手動觸發指令" tabindex="-1">四、手動觸發指令 <a class="header-anchor" href="#四、手動觸發指令" aria-label="Permalink to &quot;四、手動觸發指令&quot;">​</a></h2><p>兩個 comment 指令，在任何 repo（任何模式下）均有效：</p><table tabindex="0"><thead><tr><th>指令</th><th>效果</th></tr></thead><tbody><tr><td><code>@claude review</code></td><td>執行一次 review，並訂閱此 PR 後續 push 觸發</td></tr><tr><td><code>@claude review once</code></td><td>執行一次 review，<strong>不</strong>訂閱後續 push</td></tr></tbody></table><p>使用條件：</p><ul><li>必須是 PR <strong>頂層 comment</strong>（非 diff inline comment）</li><li>指令放在 comment 最前面</li><li>需有 repo owner / member / collaborator 存取權</li><li>PR 必須是 open 狀態（manual 模式也支援 draft PR）</li></ul><hr><h2 id="五、自訂-review-行為" tabindex="-1">五、自訂 Review 行為 <a class="header-anchor" href="#五、自訂-review-行為" aria-label="Permalink to &quot;五、自訂 Review 行為&quot;">​</a></h2><h3 id="_5-1-claude-md" tabindex="-1">5.1 CLAUDE.md <a class="header-anchor" href="#_5-1-claude-md" aria-label="Permalink to &quot;5.1 CLAUDE.md&quot;">​</a></h3><p>Code Review 讀取 repo 中所有層級的 <code>CLAUDE.md</code>，將新引入的違規標為 🟡 Nit。 支援雙向：若 PR 讓某 <code>CLAUDE.md</code> 說明過時，Claude 也會標記需更新文件。</p><h3 id="_5-2-review-md-review-專屬-最高優先" tabindex="-1">5.2 REVIEW.md（Review 專屬，最高優先） <a class="header-anchor" href="#_5-2-review-md-review-專屬-最高優先" aria-label="Permalink to &quot;5.2 REVIEW.md（Review 專屬，最高優先）&quot;">​</a></h3><p>放在 repo root 的 <code>REVIEW.md</code> 被注入到每個 review agent 的 system prompt 最高優先區塊。</p><p><strong>注意</strong>：</p><ul><li>內容逐字貼入，<code>@</code> import 語法<strong>不展開</strong></li><li>規則直接寫在檔案中，不要引用其他檔案</li></ul><h4 id="可調整的項目" tabindex="-1">可調整的項目 <a class="header-anchor" href="#可調整的項目" aria-label="Permalink to &quot;可調整的項目&quot;">​</a></h4><table tabindex="0"><thead><tr><th>項目</th><th>說明</th></tr></thead><tbody><tr><td><strong>Severity 重新定義</strong></td><td>為你的 repo 重定義什麼算 🔴 Important</td></tr><tr><td><strong>Nit 上限</strong></td><td>設定每次 review 最多幾則 Nit comment</td></tr><tr><td><strong>Skip 規則</strong></td><td>排除 generated code、lockfile、vendored 依賴、特定分支</td></tr><tr><td><strong>Repo 專屬檢查</strong></td><td>「所有新 API route 必須有 integration test」等規則</td></tr><tr><td><strong>Verification bar</strong></td><td>要求附 <code>file:line</code> 引用才能發佈某類 finding</td></tr><tr><td><strong>Re-review 收斂</strong></td><td>「第一次 review 後，只報 Important」防止 style 打 7 輪</td></tr><tr><td><strong>Summary 格式</strong></td><td>「先寫 &#39;2 factual, 4 style&#39; 摘要行再展開細節」</td></tr></tbody></table><h4 id="review-md-完整範例" tabindex="-1">REVIEW.md 完整範例 <a class="header-anchor" href="#review-md-完整範例" aria-label="Permalink to &quot;REVIEW.md 完整範例&quot;">​</a></h4><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Review instructions</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## What Important means here</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Reserve Important for findings that would break behavior, leak data,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">or block a rollback: incorrect logic, unscoped database queries, PII</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">in logs or error messages, and migrations that aren&#39;t backward</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compatible. Style, naming, and refactoring suggestions are Nit at most.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Cap the nits</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Report at most five Nits per review. If you found more, say &quot;plus N</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">similar items&quot; in the summary instead of posting them inline. If</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">everything you found is a Nit, lead the summary with &quot;No blocking issues.&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Do not report</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Anything CI already enforces: lint, formatting, type errors</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Generated files under </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`src/gen/\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> and any </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`*.lock\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> file</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Test-only code that intentionally violates production rules</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Always check</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> New API routes have an integration test</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Log lines don&#39;t include email addresses, user IDs, or request bodies</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Database queries are scoped to the caller&#39;s tenant</span></span></code></pre></div><hr><h2 id="六、用量分析" tabindex="-1">六、用量分析 <a class="header-anchor" href="#六、用量分析" aria-label="Permalink to &quot;六、用量分析&quot;">​</a></h2><p>前往 <code>claude.ai/analytics/code-review</code> 查看：</p><table tabindex="0"><thead><tr><th>區塊</th><th>內容</th></tr></thead><tbody><tr><td>PRs reviewed</td><td>每日審查 PR 數量</td></tr><tr><td>Cost weekly</td><td>每週 Code Review 費用</td></tr><tr><td>Feedback</td><td>開發者因修復而被自動解析的 comment 數</td></tr><tr><td>Repository breakdown</td><td>每個 repo 的 PR 審查數 + comment 解析數</td></tr></tbody></table><hr><h2 id="七、定價" tabindex="-1">七、定價 <a class="header-anchor" href="#七、定價" aria-label="Permalink to &quot;七、定價&quot;">​</a></h2><ul><li>按 token 用量計費，<strong>不計入</strong>訂閱內含用量（extra usage 計費）</li><li>平均每次 review：<strong>$15–25</strong>（依 PR 大小、codebase 複雜度、需驗證的問題數而異）</li><li>設定月費上限：<code>claude.ai/admin-settings/usage</code> → Claude Code Review service 的 limit</li></ul><table tabindex="0"><thead><tr><th>觸發模式</th><th>費用影響</th></tr></thead><tbody><tr><td>Once after PR creation</td><td>每 PR 一次費用</td></tr><tr><td>After every push</td><td>費用 × push 次數</td></tr><tr><td>Manual</td><td>無 review = 無費用；@claude review 後轉為 per-push</td></tr></tbody></table><hr><h2 id="八、troubleshooting" tabindex="-1">八、Troubleshooting <a class="header-anchor" href="#八、troubleshooting" aria-label="Permalink to &quot;八、Troubleshooting&quot;">​</a></h2><h3 id="_8-1-review-失敗-超時" tabindex="-1">8.1 review 失敗 / 超時 <a class="header-anchor" href="#_8-1-review-失敗-超時" aria-label="Permalink to &quot;8.1 review 失敗 / 超時&quot;">​</a></h3><p>Check run 標題顯示「Code review encountered an error」或「Code review timed out」：</p><ul><li>Comment <code>@claude review once</code> 重新觸發</li><li>GitHub Checks tab 的 <strong>Re-run</strong> 按鈕<strong>無效</strong>（不會重觸 Code Review）</li></ul><h3 id="_8-2-超過月費上限" tabindex="-1">8.2 超過月費上限 <a class="header-anchor" href="#_8-2-超過月費上限" aria-label="Permalink to &quot;8.2 超過月費上限&quot;">​</a></h3><p>PR 上出現 spend-cap message → 下個計費週期自動恢復，或 admin 在 <code>claude.ai/admin-settings/usage</code> 調高上限。</p><h3 id="_8-3-找不到-inline-comments" tabindex="-1">8.3 找不到 inline comments <a class="header-anchor" href="#_8-3-找不到-inline-comments" aria-label="Permalink to &quot;8.3 找不到 inline comments&quot;">​</a></h3><p>若 check run 顯示有 finding 但看不到 inline comments，找這些位置：</p><ul><li><strong>Check run Details</strong>：完整 finding 表格（即使 inline comment 被 GitHub 拒絕也存在）</li><li><strong>Files changed tab annotations</strong>：直接標在 diff 行上</li><li><strong>Review body「Additional findings」</strong>：review 進行中 push 導致舊行號失效的 finding</li></ul><hr><h2 id="九、與本-workspace-的整合" tabindex="-1">九、與本 Workspace 的整合 <a class="header-anchor" href="#九、與本-workspace-的整合" aria-label="Permalink to &quot;九、與本 Workspace 的整合&quot;">​</a></h2><ul><li><strong>REVIEW.md</strong> 可搭配本 workspace 的 <code>/deep-review</code> skill（本地 commit 前）使用，形成雙層 review 防線</li><li>Code Review (managed) 適合 PR 開啟後的<strong>雲端平行審查</strong>；<code>/deep-review</code> 適合 commit 前的<strong>本地三維度審查</strong></li><li><code>CLAUDE.md</code> 在兩者中共享，規則統一維護</li></ul><hr><h2 id="十、相關自動化指令" tabindex="-1">十、相關自動化指令 <a class="header-anchor" href="#十、相關自動化指令" aria-label="Permalink to &quot;十、相關自動化指令&quot;">​</a></h2><p>以下指令與 Code Review 產品互補，針對 PR 生命週期的不同環節提供自動化。</p><h3 id="pr-auto-fix-web-w13" tabindex="-1">PR Auto-Fix（Web，W13） <a class="header-anchor" href="#pr-auto-fix-web-w13" aria-label="Permalink to &quot;PR Auto-Fix（Web，W13）&quot;">​</a></h3><p>開啟 PR → CI panel 中開啟 <strong>Auto fix</strong> toggle → Claude 監控 CI，自動修復失敗，處理 review nit，持續 push 直到 green。</p><h3 id="autofix-pr-cli-w15" tabindex="-1"><code>/autofix-pr</code>（CLI，W15） <a class="header-anchor" href="#autofix-pr-cli-w15" aria-label="Permalink to &quot;\`/autofix-pr\`（CLI，W15）&quot;">​</a></h3><p>不需開瀏覽器，從 terminal 一鍵對當前分支的 PR 啟動 Auto-Fix：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /autofix-pr</span></span></code></pre></div><h3 id="ultrareview-w16-v2-1-111-w17-公開-preview" tabindex="-1"><code>/ultrareview</code>（W16 v2.1.111，W17 公開 Preview） <a class="header-anchor" href="#ultrareview-w16-v2-1-111-w17-公開-preview" aria-label="Permalink to &quot;\`/ultrareview\`（W16 v2.1.111，W17 公開 Preview）&quot;">​</a></h3><p>在雲端平行執行多個 reviewer agent，再跑 adversarial critique pass 過濾誤報，結果回傳 CLI：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /ultrareview           # review 當前分支</span></span>
<span class="line"><span>&gt; /ultrareview 1234      # review 指定 PR 號碼</span></span></code></pre></div><p>W17 進入 public research preview，launch dialog 顯示 diffstat。</p><h3 id="claude-ultrareview-cli-子命令-w18" tabindex="-1"><code>claude ultrareview</code>（CLI 子命令，W18） <a class="header-anchor" href="#claude-ultrareview-cli-子命令-w18" aria-label="Permalink to &quot;\`claude ultrareview\`（CLI 子命令，W18）&quot;">​</a></h3><p>非互動式的 <code>/ultrareview</code>，可在 CI/scripts 中使用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ultrareview</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 輸出結構化結果</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ultrareview</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 輸出原始 JSON</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># exit 0 成功，exit 1 失敗</span></span></code></pre></div><h3 id="simplify-2026-02-28-boris-cherny" tabindex="-1"><code>/simplify</code>（2026-02-28，Boris Cherny） <a class="header-anchor" href="#simplify-2026-02-28-boris-cherny" aria-label="Permalink to &quot;\`/simplify\`（2026-02-28，Boris Cherny）&quot;">​</a></h3><p>PR 完成後對已變更程式碼進行 review for reuse / quality / efficiency，自動精煉並提交改善。Boris Cherny 個人日常使用驗證：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /simplify</span></span></code></pre></div><p>適用時機：PR 草稿完成後發 PR 之前、收到「這段能否簡化」的 review 意見後。</p><hr><h2 id="known-gotchas" tabindex="-1">Known Gotchas <a class="header-anchor" href="#known-gotchas" aria-label="Permalink to &quot;Known Gotchas&quot;">​</a></h2><ul><li><code>@claude review</code> 在 <strong>draft PR</strong> 不觸發（除非在 Manual 模式下手動指定）</li><li><code>REVIEW.md</code> 的 <code>@import</code> 語法無效，規則必須直接寫入</li><li>check run 結論永遠 neutral，無法直接用作 branch protection rule → 需用 <code>gh</code> + jq 解析 severity JSON 自建 gate</li><li>Re-run 按鈕無法重觸 Code Review，務必用 comment 指令</li></ul>`,88)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
